// Stateless async-job tokens. The API is read-only and deterministic, so a
// "job" is fully described by its request: the job id IS the request,
// base64url-encoded. GET /api/jobs/<token> re-derives and executes it —
// idempotent by construction, no queue or store needed, and the status
// endpoint always reflects the job's true state.

const MAX_TOKEN_CHARS = 4096;

export type JobSpec = {
	v: 1;
	kind: "md-batch";
	paths: string[];
};

export function encodeJobToken(spec: JobSpec): string {
	return Buffer.from(JSON.stringify(spec), "utf8").toString("base64url");
}

export function decodeJobToken(token: string): JobSpec | null {
	if (!token || token.length > MAX_TOKEN_CHARS || !/^[A-Za-z0-9_-]+$/.test(token)) {
		return null;
	}
	let parsed: unknown;
	try {
		parsed = JSON.parse(Buffer.from(token, "base64url").toString("utf8"));
	} catch {
		return null;
	}
	if (typeof parsed !== "object" || parsed === null) return null;
	const spec = parsed as Record<string, unknown>;
	if (spec.v !== 1 || spec.kind !== "md-batch") return null;
	if (
		!Array.isArray(spec.paths) ||
		spec.paths.length === 0 ||
		!spec.paths.every((p) => typeof p === "string")
	) {
		return null;
	}
	return { v: 1, kind: "md-batch", paths: spec.paths as string[] };
}
